app.post("/api/member-requests/:id/approve", async (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) return res.status(401).json({ error: "Unauthorized" });

  const token = authHeader.split(" ")[1];
  try {
    const supabase = getSupabaseClient(token);
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    if (authError || !user) throw new Error("Invalid token");

    const { id } = req.params;

    // 1. Fetch the member request
    const { data: request, error: fetchError } = await supabaseAdmin
      .from("member_requests")
      .select("*, profiles(organization_id)") // Select organization_id from profiles table
      .eq("id", id)
      .single();

    if (fetchError || !request) {
      return res.status(404).json({ error: "Member request not found" });
    }

    // Ensure the user has permission for this organization
    const userProfileResponse = await supabaseAdmin
      .from("profiles")
      .select("organization_id, id")
      .eq("id", user.id)
      .single();

    if (userProfileResponse.error || !userProfileResponse.data) {
      throw new Error("User profile not found or unauthorized");
    }

    if (request.organization_id !== userProfileResponse.data.organization_id) {
      return res.status(403).json({ error: "Unauthorized to approve this request" });
    }

    // 2. Create new member from form_data
    const formData = request.form_data;
    const dbMemberData: any = {
      email: formData.email,
      phone_number: formData.phone || formData.phoneNumber || '',
      address: formData.address || formData.location || '',
      emergency_contact_name: formData.emergency_contact_name || formData.emergencyContactName || '',
      emergency_contact_phone: formData.emergency_contact_phone || formData.emergencyContactPhone || '',
      dob: formData.dob || formData.dateOfBirth || null,
      memberimage_url: formData.member_url || formData.memberUrl || formData.profileImage || null,
      organization_id: request.organization_id,
      branch_id: request.branch_id,
      date_joined: formData.date_joined || formData.dateJoined || new Date().toISOString().split('T')[0],
      member_id_string: formData.member_id_string || formData.memberIdString || '',
      status: 'active',
      first_name: formData.first_name || (formData.fullName ? formData.fullName.split(' ')[0] : 'Unknown'),
      last_name: formData.last_name || (formData.fullName ? formData.fullName.split(' ').slice(1).join(' ') : ''),
      gender: formData.gender || null,
      marital_status: formData.marital_status || null,
      occupation: formData.occupation || null
    };

    const { data: newMember, error: memberError } = await supabaseAdmin
      .from("members")
      .insert([dbMemberData])
      .select()
      .single();

    if (memberError) throw memberError;

    // 3. Update member_requests status
    const { data: updatedRequest, error: updateError } = await supabaseAdmin
      .from("member_requests")
      .update({ status: "approved", reviewed_by: user.id, updated_at: new Date().toISOString() })
      .eq("id", id)
      .select()
      .single();

    if (updateError) throw updateError;

    res.status(200).json({ message: "Member approved successfully", member: newMember, request: updatedRequest });

  } catch (error: any) {
    console.error("Error approving member request:", error);
    res.status(500).json({ error: error.message || "Failed to approve member request" });
  }
});

app.post("/api/member-requests/:id/reject", async (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) return res.status(401).json({ error: "Unauthorized" });

  const token = authHeader.split(" ")[1];
  try {
    const supabase = getSupabaseClient(token);
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    if (authError || !user) throw new Error("Invalid token");

    const { id } = req.params;

    // Fetch the request to verify organization_id
    const { data: request, error: fetchError } = await supabaseAdmin
      .from("member_requests")
      .select("organization_id")
      .eq("id", id)
      .single();

    if (fetchError || !request) {
      return res.status(404).json({ error: "Member request not found" });
    }

    const userProfileResponse = await supabaseAdmin
      .from("profiles")
      .select("organization_id, id")
      .eq("id", user.id)
      .single();

    if (userProfileResponse.error || !userProfileResponse.data) {
      throw new Error("User profile not found or unauthorized");
    }

    if (request.organization_id !== userProfileResponse.data.organization_id) {
      return res.status(403).json({ error: "Unauthorized to reject this request" });
    }

    // Update member_requests status to rejected
    const { data: updatedRequest, error: updateError } = await supabaseAdmin
      .from("member_requests")
      .update({ status: "rejected", reviewed_by: user.id, updated_at: new Date().toISOString() })
      .eq("id", id)
      .select()
      .single();

    if (updateError) throw updateError;

    res.status(200).json({ message: "Member request rejected", request: updatedRequest });

  } catch (error: any) {
    console.error("Error rejecting member request:", error);
    res.status(500).json({ error: error.message || "Failed to reject member request" });
  }
});

