const handleSaveMember = async (memberData: Partial<Member>) => {
  if (!token) {
    toast.error('Authentication session expired. Please log in again.');
    return;
  }

  const branchId = selectedBranch?.id || user?.branch_id || (branches.length > 0 ? branches[0].id : null);

  if (!branchId) {
    toast.error('Please select a branch first.');
    return;
  }

  try {
    const payload: any = {
      first_name: memberData.first_name,
      last_name: memberData.last_name,
      email: memberData.email,
      phone: memberData.phone,
      address: memberData.address,
      emergency_contact_name: memberData.emergency_contact_name,
      emergency_contact_phone: memberData.emergency_contact_phone,
      member_url: memberData.member_url,
      dob: memberData.dob,
      gender: memberData.gender,
      marital_status: memberData.marital_status,
      occupation: memberData.occupation,
      member_id_string: memberData.member_id_string,
      status: memberData.status,
      date_joined: memberData.date_joined,
      branch_id: branchId,
    };

    // Handle legacy field mapping if they were passed instead
    if (!payload.first_name && memberData.fullName) {
      const nameParts = (memberData.fullName || '').split(' ');
      payload.first_name = nameParts[0] || '';
      payload.last_name = nameParts.slice(1).join(' ') || '';
    }
    if (!payload.phone && memberData.phoneNumber) payload.phone = memberData.phoneNumber;
    if (!payload.address && memberData.location) payload.address = memberData.location;
    if (!payload.emergency_contact_phone && memberData.emergencyContact) payload.emergency_contact_phone = memberData.emergencyContact;
    if (!payload.member_url && memberData.memberUrl) payload.member_url = memberData.memberUrl;

    const payloadStr = JSON.stringify(payload);
    console.log(`Saving member. Payload size: ${(payloadStr.length / 1024).toFixed(2)} KB`);
    console.log('Payload:', payload);

    const response = await fetch(editingMember ? `/api/members/${editingMember.id}` : '/api/members', {
      method: editingMember ? 'PUT' : 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      if (response.status === 413) {
        toast.error('The image is too large. Please use a smaller image.');
        throw new Error('Image too large (413)');
      }
      const errorData = await response.json().catch(() => ({}));
      console.error('Full server error response:', errorData);
      throw new Error(errorData.error || errorData.message || 'Failed to save member');
    }

    toast.success(editingMember ? 'Member updated successfully!' : 'Member added successfully!');
    fetchMembers();
    setEditingMember(undefined);
    setIsAddModalOpen(false);
  } catch (error: any) {
    console.error('Error saving member:', error);
    toast.error(error.message || 'Failed to save member');
  }
};

