app.get("/api/ministries", async (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) return res.status(401).json({ error: "Unauthorized" });

  const token = authHeader.split(" ")[1];
  try {
    const supabase = getSupabaseClient(token);
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    if (authError || !user) throw new Error("Invalid token");

    const { data: userProfile } = await supabaseAdmin
      .from("profiles")
      .select("organization_id")
      .eq("id", user.id)
      .single();

    if (!userProfile) throw new Error("User profile not found");

    const { branch_id } = req.query;

    let query = supabaseAdmin
      .from("groups")
      .select("*, leader:profiles(id, first_name, last_name, avatar_url)")
      .eq("organization_id", userProfile.organization_id)
      .eq("group_type", 'ministry');

    if (branch_id) {
      query = query.eq("branch_id", branch_id);
    }

    const { data: ministries, error } = await query;

    if (error) throw error;
    res.json(ministries);
  } catch (error: any) {
    console.error("Error fetching ministries:", error);
    res.status(500).json({ error: error.message || "Failed to fetch ministries" });
  }
});

