import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Group } from '../../utils/supabase'; // Assuming Group interface is here
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'sonner';

const MinistryDetail: React.FC = () => {
  const { groupId } = useParams<{ groupId: string }>();
  const { token } = useAuth();

  const [group, setGroup] = useState<Group | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!groupId || !token) {
      setLoading(false);
      return;
    }

    const fetchGroupDetails = async () => {
      setLoading(true);
      setError(null);
      try {
        const response = await fetch(`http://localhost:3000/api/groups/${groupId}`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });
        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(errorData.error || 'Failed to fetch group details');
        }
        const data = await response.json();
        setGroup(data);
      } catch (err: any) {
        console.error("Error fetching group details:", err);
        setError(err.message);
        toast.error(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchGroupDetails();
  }, [groupId, token]);

  if (loading) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-gray-600">Loading ministry details...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-red-500">Error: {error}</p>
      </div>
    );
  };

  if (!group) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <h1 className="text-3xl font-bold text-gray-900">Ministry Not Found</h1>
        <p className="mt-2 text-gray-600">The requested ministry could not be found.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col flex-1 p-6">
      <h1 className="text-3xl font-bold text-gray-900">Ministry Detail: {group.name}</h1>
      <p className="mt-2 text-gray-600">Type: {group.group_type}</p>
      {group.description && <p className="mt-1 text-gray-600">Description: {group.description}</p>}
      {group.leader_id && <p className="mt-1 text-gray-600">Leader: {group.profiles?.first_name} {group.profiles?.last_name}</p>}
      {group.parent_group_id && <p className="mt-1 text-gray-600">Parent Group ID: {group.parent_group_id}</p>}
    </div>
  );
};

export default MinistryDetail;

