import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'sonner';
import { Member } from '../../utils/supabase'; // Assuming Member interface is here

interface AddMembersModalProps {
  isOpen: boolean;
  onClose: () => void;
  groupId: string;
  onMembersAdded: () => void;
}

const AddMembersModal: React.FC<AddMembersModalProps> = ({
  isOpen,
  onClose,
  groupId,
  onMembersAdded,
}) => {
  const { token } = useAuth();
  const [availableMembers, setAvailableMembers] = useState<Member[]>([]);
  const [selectedMembers, setSelectedMembers] = useState<Set<string>>(new Set());
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [role, setRole] = useState<'member' | 'leader' | 'co-leader'>('member');

  useEffect(() => {
    if (!isOpen || !token || !groupId) return;

    const fetchAvailableMembers = async () => {
      setLoading(true);
      setError(null);
      try {
        const response = await fetch(
          `http://localhost:3000/api/members?not_in_group_id=${groupId}`,
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );
        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(errorData.error || 'Failed to fetch available members');
        }
        const data = await response.json();
        setAvailableMembers(data);
      } catch (err: any) {
        console.error("Error fetching available members:", err);
        setError(err.message);
        toast.error(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchAvailableMembers();
  }, [isOpen, token, groupId]);

  const handleSelectMember = (memberId: string) => {
    setSelectedMembers((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(memberId)) {
        newSet.delete(memberId);
      } else {
        newSet.add(memberId);
      }
      return newSet;
    });
  };

  const handleAddMembers = async () => {
    if (selectedMembers.size === 0) {
      toast.info("Please select at least one member.");
      return;
    }

    if (!token || !groupId) return;

    try {
      const memberAddPromises = Array.from(selectedMembers).map(async (memberId) => {
        const response = await fetch(`http://localhost:3000/api/group-members`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({
            group_id: groupId,
            member_id: memberId,
            role_in_group: role,
          }),
        });

        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(
            errorData.error || `Failed to add member ${memberId} to group`
          );
        }
        return response.json();
      });

      await Promise.all(memberAddPromises);
      toast.success(`${selectedMembers.size} member(s) added successfully!`);
      onMembersAdded(); // Refresh parent component's member list
      onClose();
      setSelectedMembers(new Set()); // Clear selection
    } catch (err: any) {
      console.error("Error adding members to group:", err);
      toast.error(err.message);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-md">
        <h2 className="text-2xl font-bold mb-4">Add Members to Group</h2>

        {loading ? (
          <p className="text-gray-600">Loading available members...</p>
        ) : error ? (
          <p className="text-red-500">Error: {error}</p>
        ) : availableMembers.length === 0 ? (
          <p className="text-gray-600">No new members available to add.</p>
        ) : (
          <div className="mb-4 max-h-60 overflow-y-auto border rounded-md p-2">
            {availableMembers.map((member) => (
              <div key={member.id} className="flex items-center justify-between py-2 border-b last:border-b-0">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={selectedMembers.has(member.id)}
                    onChange={() => handleSelectMember(member.id)}
                    className="form-checkbox h-4 w-4 text-indigo-600 transition duration-150 ease-in-out"
                  />
                  <span className="text-gray-900">{member.first_name} {member.last_name}</span>
                </label>
              </div>
            ))}
          </div>
        )}

        <div className="mb-4">
          <label htmlFor="role" className="block text-sm font-medium text-gray-700">Assign Role:</label>
          <select
            id="role"
            name="role"
            value={role}
            onChange={(e) => setRole(e.target.value as 'member' | 'leader' | 'co-leader')}
            className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
          >
            <option value="member">Member</option>
            <option value="leader">Leader</option>
            <option value="co-leader">Co-Leader</option>
          </select>
        </div>

        <div className="flex justify-end space-x-3">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
          >
            Cancel
          </button>
          <button
            onClick={handleAddMembers}
            className="px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            disabled={selectedMembers.size === 0 || loading}
          >
            Add Selected Members
          </button>
        </div>
      </div>
    </div>
  );
};

export default AddMembersModal;

