      return newSet;
    });
  };

  const handleAssignToGroups = async () => {
    if (selectedGroups.size === 0) {
      toast.info("Please select at least one group.");
      return;
    }

    if (!token || !memberId) return;

    try {
      const assignmentPromises = Array.from(selectedGroups).map(async (groupId) => {
        const response = await fetch(`http://localhost:3000/api/group-members`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({
            group_id: groupId,
            member_id: memberId,
            role_in_group: role,
          }),
        });

        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(
            errorData.error || `Failed to assign member to group ${groupId}`
          );
        }
        return response.json();
      });

      await Promise.all(assignmentPromises);
      toast.success(`${selectedGroups.size} group(s) assigned successfully!`);
      onAssignmentComplete(); 
      onClose();
      setSelectedGroups(new Set()); 
    } catch (err: any) {
      console.error("Error assigning member to groups:", err);
      toast.error(err.message);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-md">
        <h2 className="text-2xl font-bold mb-4">Assign Member to Group</h2>

        {loading ? (
          <p className="text-gray-600">Loading available groups...</p>
        ) : error ? (
          <p className="text-red-500">Error: {error}</p>
        ) : availableGroups.length === 0 ? (
          <p className="text-gray-600">No groups available to assign.</p>
        ) : (
          <div className="mb-4 max-h-60 overflow-y-auto border rounded-md p-2">
            {availableGroups.map((group) => (
              <div key={group.id} className="flex items-center justify-between py-2 border-b last:border-b-0">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={selectedGroups.has(group.id)}
                    onChange={() => handleSelectGroup(group.id)}
                    className="form-checkbox h-4 w-4 text-indigo-600 transition duration-150 ease-in-out"
                  />
                  <span className="text-gray-900">{group.name} ({group.group_type})</span>
                </label>
              </div>
            ))}
          </div>
        )}

        <div className="mb-4">
          <label htmlFor="role" className="block text-sm font-medium text-gray-700">Assign Role:</label>
          <select
            id="role"
            name="role"
            value={role}
            onChange={(e) => setRole(e.target.value as 'member' | 'leader' | 'co-leader')}
            className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
          >
            <option value="member">Member</option>
            <option value="leader">Leader</option>
            <option value="co-leader">Co-Leader</option>
          </select>
        </div>

        <div className="flex justify-end space-x-3">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
          >
            Cancel
          </button>
          <button
            onClick={handleAssignToGroups}
            className="px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            disabled={selectedGroups.size === 0 || loading}
          >
            Assign to Selected Groups
          </button>
        </div>
      </div>
    </div>
  );
};

