import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Group } from '../../utils/supabase'; // Assuming Group interface is here
import { toast } from 'sonner';

interface PublicGroupData extends Omit<Group, 'created_at' | 'updated_at' | 'organization_id' | 'branch_id' | 'is_deleted' | 'deleted_at' | 'leader_id' | 'parent_group_id' | 'public_website_enabled' | 'join_link_enabled'> {
  leader_first_name?: string;
  leader_last_name?: string;
}

const JoinGroupPage: React.FC = () => {
  const { groupId } = useParams<{ groupId: string }>();
  const [groupData, setGroupData] = useState<PublicGroupData | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [fullName, setFullName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [phone, setPhone] = useState<string>('');
  const [message, setMessage] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  useEffect(() => {
    const fetchPublicGroupDetails = async () => {
      if (!groupId) return;
      setLoading(true);
      setError(null);
      try {
        const response = await fetch(`http://localhost:3000/api/public/groups/${groupId}`);
        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(errorData.error || 'Failed to fetch public group details');
        }
        const data: Group & { profiles: { first_name: string, last_name: string } } = await response.json();

        setGroupData({
          id: data.id,
          name: data.name,
          description: data.description,
          group_type: data.group_type,
          cover_image_url: data.cover_image_url,
          announcements_content: data.announcements_content,
          program_outline_content: data.program_outline_content,
          contact_email: data.contact_email,
          contact_phone: data.contact_phone,
          public_link_slug: data.public_link_slug,
          leader_first_name: data.profiles?.first_name,
          leader_last_name: data.profiles?.last_name,
        });
      } catch (err: any) {
        console.error("Error fetching public group details:", err);
        setError(err.message);
        toast.error(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchPublicGroupDetails();
  }, [groupId]);

  const handleSubmitRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupId || !fullName || !email) {
      toast.error('Please fill in all required fields (Full Name, Email).');
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch(`http://localhost:3000/api/group-requests`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          group_id: groupId,
          full_name: fullName,
          email: email,
          phone: phone,
          message: message,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to submit join request');
      }

      toast.success('Your join request has been submitted successfully! We will get back to you soon.');
      setFullName('');
      setEmail('');
      setPhone('');
      setMessage('');
    } catch (err: any) {
      console.error('Error submitting join request:', err);
      toast.error(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-gray-600">Loading group information...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-red-500">Error: {error}</p>
      </div>
    );
  }

  if (!groupData) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <h1 className="text-3xl font-bold text-gray-900">Group Not Found</h1>
        <p className="mt-2 text-gray-600">The requested group could not be found or does not have join links enabled.</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-6 flex items-center justify-center">
      <div className="bg-white shadow-xl rounded-lg overflow-hidden max-w-4xl w-full">
        {groupData.cover_image_url && (
          <img src={groupData.cover_image_url} alt={`${groupData.name} Cover`} className="w-full h-48 object-cover" />
        )}
        <div className="p-8">
          <h1 className="text-4xl font-extrabold text-gray-900 mb-4">Join {groupData.name}</h1>
          <p className="text-gray-700 text-lg mb-6">{groupData.description}</p>

          <div className="mb-8 border-t border-gray-200 pt-6">
            <h2 className="text-2xl font-bold text-gray-800 mb-4">Send a Join Request</h2>
            <form onSubmit={handleSubmitRequest} className="space-y-4">
              <div>
                <label htmlFor="fullName" className="block text-sm font-medium text-gray-700">Full Name <span className="text-red-500">*</span></label>
                <input
                  type="text"
                  id="fullName"
                  value={fullName}
                  onChange={(e) => setFullName(e.target.value)}
                  className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                  required
                />
              </div>
              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700">Email <span className="text-red-500">*</span></label>
                <input
                  type="email"
                  id="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                  required
                />
              </div>
              <div>
                <label htmlFor="phone" className="block text-sm font-medium text-gray-700">Phone (Optional)</label>
                <input
                  type="tel"
                  id="phone"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                />
              </div>
              <div>
                <label htmlFor="message" className="block text-sm font-medium text-gray-700">Message (Optional)</label>
                <textarea
                  id="message"
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  rows={4}
                  className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                ></textarea>
              </div>
              <button
                type="submit"
                disabled={isSubmitting}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-lg font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting ? 'Submitting...' : 'Submit Join Request'}
              </button>
            </form>
          </div>

          {groupData.announcements_content && (
            <div className="mt-8 border-t border-gray-200 pt-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Announcements</h2>
              <div className="prose max-w-none" dangerouslySetInnerHTML={{ __html: groupData.announcements_content }} />
            </div>
          )}

          {groupData.program_outline_content && (
            <div className="mt-8 border-t border-gray-200 pt-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Program Outline</h2>
              <div className="prose max-w-none" dangerouslySetInnerHTML={{ __html: groupData.program_outline_content }} />
            </div>
          )}

          {(groupData.contact_email || groupData.contact_phone) && (
            <div className="mt-8 border-t border-gray-200 pt-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Contact Us</h2>
              {groupData.contact_email && <p className="text-gray-700">Email: <a href={`mailto:${groupData.contact_email}`} className="text-indigo-600 hover:underline">{groupData.contact_email}</a></p>}
              {groupData.contact_phone && <p className="text-gray-700">Phone: {groupData.contact_phone}</p>}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default JoinGroupPage;

