  const [requests, setRequests] = useState<GroupRequestWithGroup[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchGroupRequests = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(`http://localhost:3000/api/group-requests?status=pending`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to fetch group join requests');
      }
      const data: GroupRequestWithGroup[] = await response.json();
      setRequests(data);
    } catch (err: any) {
      console.error("Error fetching group join requests:", err);
      setError(err.message);
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (token) {
      fetchGroupRequests();
    }
  }, [token]);

  const handleApproveRequest = async (requestId: string, groupId: string, memberData: any) => {
    if (!window.confirm("Are you sure you want to approve this request and add the member to the group?")) return;
    if (!token) return;

    try {
      // First, create the member (if not already existing, or link existing member)
      // For now, let's assume we create a new member. This logic might need refinement later
      // to check for existing members with the same email/phone.
      const memberPayload = {
        first_name: memberData.full_name.split(' ')[0] || 'Unknown',
        last_name: memberData.full_name.split(' ').slice(1).join(' ') || '',
        email: memberData.email,
        phone_number: memberData.phone || '',
        organization_id: userProfile?.organization_id, // Assuming userProfile is available
        branch_id: userProfile?.branch_id, // Assuming userProfile is available
        status: 'active',
      };

      const memberResponse = await fetch(`http://localhost:3000/api/members`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(memberPayload),
      });

      if (!memberResponse.ok) {
        const errorData = await memberResponse.json();
        throw new Error(errorData.error || 'Failed to create new member');
      }
      const newMember = await memberResponse.json();

      // Then, add the newly created member to the group
      const addGroupMemberResponse = await fetch(`http://localhost:3000/api/group-members`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          group_id: groupId,
          member_id: newMember.id,
          role_in_group: 'member', // Default role for new join requests
        }),
      });

      if (!addGroupMemberResponse.ok) {
        const errorData = await addGroupMemberResponse.json();
        throw new Error(errorData.error || 'Failed to add member to group');
      }

      // Finally, update the request status to approved
      const approveResponse = await fetch(`http://localhost:3000/api/group-requests/${requestId}/approve`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!approveResponse.ok) {
        const errorData = await approveResponse.json();
        throw new Error(errorData.error || 'Failed to approve join request');
      }

      toast.success("Join request approved and member added to group!");
      fetchGroupRequests(); // Refresh the list
    } catch (err: any) {
      console.error("Error approving request:", err);
      toast.error(err.message);
    }
  };

  const handleRejectRequest = async (requestId: string) => {
    if (!window.confirm("Are you sure you want to reject this request?")) return;
    if (!token) return;

    try {
      const response = await fetch(`http://localhost:3000/api/group-requests/${requestId}/reject`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to reject join request');
      }

      toast.success("Join request rejected.");
      fetchGroupRequests(); // Refresh the list
    } catch (err: any) {
      console.error("Error rejecting request:", err);
      toast.error(err.message);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-gray-600">Loading join requests...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col flex-1 p-6 items-center justify-center">
        <p className="text-red-500">Error: {error}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col flex-1 p-6">
      <h1 className="text-3xl font-bold text-gray-900 mb-6">Group Join Requests</h1>

      {requests.length === 0 ? (
        <p className="text-gray-600">No pending group join requests.</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {requests.map((request) => (
            <div key={request.id} className="bg-white shadow-md rounded-lg p-6 flex flex-col justify-between">
              <div>
                <h2 className="text-xl font-semibold text-gray-800 mb-2">Request for {request.groups?.name || 'Unknown Group'}</h2>
                <p className="text-gray-700"><strong>Name:</strong> {request.full_name}</p>
                <p className="text-gray-700"><strong>Email:</strong> {request.email}</p>
                {request.phone && <p className="text-gray-700"><strong>Phone:</strong> {request.phone}</p>}
                {request.message && <p className="text-gray-700"><strong>Message:</strong> {request.message}</p>}
                <p className="text-gray-500 text-sm mt-2">Requested on: {new Date(request.created_at).toLocaleDateString()}</p>
              </div>
              <div className="mt-4 flex space-x-2">
                <button
                  onClick={() => handleApproveRequest(request.id, request.group_id, request)}
                  className="flex-1 inline-flex items-center justify-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
                >
                  <CheckCircle className="w-5 h-5 mr-2" /> Approve
                </button>
                <button
                  onClick={() => handleRejectRequest(request.id)}
                  className="flex-1 inline-flex items-center justify-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                >
                  <XCircle className="w-5 h-5 mr-2" /> Reject
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

