app.post("/api/auth/signup", async (req, res) => {
  console.log(">>> SIGNUP REQUEST RECEIVED:", req.body.email);
  const { email, password, organizationName, fullName } = req.body;

  try {
    console.log("1. Creating user in Supabase Auth...");
    const { data: authData, error: authError } = await supabaseAdmin.auth.admin.createUser({
      email,
      password,
      email_confirm: true,
      user_metadata: { full_name: fullName }
    });

    if (authError) {
      console.error("❌ Supabase Auth signup error:", authError);
      return res.status(400).json({ error: authError.message });
    }

    const userId = authData.user.id;
    console.log("✅ User created with ID:", userId);

    console.log("2. Creating organization...");
    let orgSlug = generateSlug(organizationName || "organization");
    orgSlug = `${orgSlug}-${Math.random().toString(36).substring(2, 7)}`;

    const { data: org, error: orgError } = await supabaseAdmin
      .from("organizations")
      .insert([{ 
        name: organizationName || "My Organization",
        slug: orgSlug,
        subscription_tier: 'free'
      }])
      .select()
      .single();

    if (orgError) {
      console.error("❌ Organization creation error:", orgError);
      await supabaseAdmin.auth.admin.deleteUser(userId);
      return res.status(500).json({ error: "Failed to create organization", details: orgError.message });
    }
    console.log("✅ Organization created:", org.id);

    console.log("3. Creating default branch...");
    const { data: branch, error: branchError } = await supabaseAdmin
      .from("branches")
      .insert([{ 
        organization_id: org.id, 
        name: "Main Branch",
        is_main_branch: true
      }])
      .select()
      .single();

    if (branchError) {
      console.error("❌ Branch creation error:", branchError);
      await supabaseAdmin.auth.admin.deleteUser(userId);
      return res.status(500).json({ error: "Failed to create branch", details: branchError.message });
    }
    console.log("✅ Branch created:", branch.id);

    console.log("4. Creating user profile...");
    const nameParts = (fullName || "User").split(' ');
    const firstName = nameParts[0];
    const lastName = nameParts.length > 1 ? nameParts.slice(1).join(' ') : "User";

    const { data: userProfile, error: userError } = await supabaseAdmin
      .from("profiles")
      .insert([{
        id: userId,
        email: email,
        first_name: firstName,
        last_name: lastName,
        full_name: fullName,
        organization_id: org.id,
        branch_id: branch.id
      }])
      .select()
      .single();

    if (userError) {
      console.error("❌ User profile creation error:", userError);
      await supabaseAdmin.auth.admin.deleteUser(userId);
      return res.status(500).json({ error: "Failed to create user profile", details: userError.message });
    }
    console.log("✅ User profile created");

    console.log("5. Signing in to get session...");
    const supabaseAnon = getSupabaseClient();
    const { data: signInData, error: signInError } = await supabaseAnon.auth.signInWithPassword({
      email,
      password
    });

    if (signInError) {
      console.error("❌ Sign in error after signup:", signInError);
      return res.status(201).json({ 
        message: "User created successfully, but automatic sign-in failed. Please sign in manually.",
        user: { 
          id: userProfile.id, 
          email: userProfile.email, 
          first_name: userProfile.first_name,
          last_name: userProfile.last_name,
          organization_id: org.id,
          branch_id: branch.id
        } 
      });
    }

    console.log("✅ Signup flow complete, sending response");
    res.status(201).json({ 
      token: signInData?.session?.access_token, 
      user: { 
        id: userProfile.id, 
        email: userProfile.email, 
        first_name: userProfile.first_name,
        last_name: userProfile.last_name,
        organization_id: org.id,
        branch_id: branch.id
      } 
    });
