    console.error("💥 UNEXPECTED SIGNUP ERROR:", error);
    res.status(500).json({ error: error.message || "Internal server error" });
  }
});

app.post("/api/auth/login", async (req, res) => {
  console.log(">>> LOGIN REQUEST RECEIVED:", req.body.email);
  const { email, password } = req.body;

  try {
    console.log("1. Authenticating with Supabase Auth (using anon client)...");
    const supabaseAnon = getSupabaseClient();
    const { data: authData, error: authError } = await supabaseAnon.auth.signInWithPassword({
      email,
      password
    });

    if (authError) {
      console.error("❌ Supabase Auth login error:", authError);
      return res.status(401).json({ error: authError.message || "Invalid credentials" });
    }

    if (!authData.session) {
      console.error("❌ Login successful but no session returned");
      return res.status(401).json({ error: "Authentication successful but no session was created. Please check if email confirmation is required." });
    }

    const token = authData.session.access_token;
    const userId = authData.user.id;
    console.log("✅ Auth successful, User ID:", userId);

    console.log("2. Fetching user profile...");
    const { data: userProfile, error: userError } = await supabaseAdmin
      .from("profiles")
      .select("*")
      .eq("id", userId)
      .single();

    if (userError) {
      console.error("❌ User profile fetch error:", userError);
      return res.status(404).json({ error: "User profile not found", details: userError.message });
    }

    if (!userProfile) {
      console.error("❌ User profile not found (empty result)");
      return res.status(404).json({ error: "User profile not found" });
    }

    console.log("✅ Login flow complete, sending response");
    res.json({ 
      token, 
      user: { 
        id: userProfile.id, 
        email: userProfile.email, 
        first_name: userProfile.first_name,
        last_name: userProfile.last_name,
        organization_id: userProfile.organization_id,
        branch_id: userProfile.branch_id
      } 
    });
  } catch (error: any) {
    console.error("💥 UNEXPECTED LOGIN ERROR:", error);
    res.status(500).json({ error: "Internal server error", details: error.message });
  }
});

