app.post("/api/group-requests/:id/approve", async (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) return res.status(401).json({ error: "Unauthorized" });

  const token = authHeader.split(" ")[1];
  try {
    const supabase = getSupabaseClient(token);
    const { data: { user }, error: authError } = await supabase.auth.getUser();
    if (authError || !user) throw new Error("Invalid token");

    const { id } = req.params;

    const { data: request, error: fetchError } = await supabaseAdmin
      .from("group_requests")
      .select("*, groups(organization_id, branch_id)")
      .eq("id", id)
      .single();

    if (fetchError || !request) {
      return res.status(404).json({ error: "Group request not found" });
    }

    const userProfileResponse = await supabaseAdmin
      .from("profiles")
      .select("organization_id, branch_id, id")
      .eq("id", user.id)
      .single();

    if (userProfileResponse.error || !userProfileResponse.data) {
      throw new Error("User profile not found or unauthorized");
    }

    if (request.organization_id !== userProfileResponse.data.organization_id || request.branch_id !== userProfileResponse.data.branch_id) {
      return res.status(403).json({ error: "Unauthorized to approve this request" });
    }

    const { data: updatedRequest, error: updateError } = await supabaseAdmin
      .from("group_requests")
      .update({ status: "approved", reviewed_by: user.id, updated_at: new Date().toISOString() })
      .eq("id", id)
      .select()
      .single();

    if (updateError) throw updateError;

    const dbMemberData = {
      first_name: request.full_name.split(' ')[0] || 'Unknown',
      last_name: request.full_name.split(' ').slice(1).join(' ') || '',
      email: request.email,
      phone_number: request.phone || '',
      organization_id: request.organization_id,
      branch_id: request.branch_id,
      status: 'active',
    };

    const { data: newMember, error: memberError } = await supabaseAdmin
      .from("members")
      .insert([dbMemberData])
      .select()
      .single();

    if (memberError) {
      console.error("Supabase error creating member from group request:", memberError);
      return res.status(500).json({ error: memberError.message || "Failed to create new member" });
    }

    const { error: addMemberError } = await supabaseAdmin
      .from("group_members")
      .insert([{ group_id: request.group_id, member_id: newMember.id, role_in_group: 'member', organization_id: request.organization_id, branch_id: request.branch_id }])
      .select()
      .single();

    if (addMemberError) {
      console.error("Supabase error adding member to group:", addMemberError);
      return res.status(500).json({ error: addMemberError.message || "Failed to add member to group" });
    }

    res.status(200).json({ message: "Group join request approved, member created and added to group", member: newMember, request: updatedRequest });

  } catch (error: any) {
    console.error("Error approving group request:", error);
    res.status(500).json({ error: error.message || "Failed to approve group request" });
  }
});

