    const { data: updatedRequest, error: updateError } = await supabaseAdmin
      .from("member_requests")
      .update({ status: "rejected", reviewed_by: user.id, updated_at: new Date().toISOString() })
      .eq("id", id)
      .select()
      .single();

    if (updateError) throw updateError;

    res.status(200).json({ message: "Member request rejected", request: updatedRequest });

  } catch (error: any) {
    console.error("Error rejecting member request:", error);
    res.status(500).json({ error: error.message || "Failed to reject member request" });
  }
});

app.get("/api/public/groups/:slug", async (req, res) => {
  try {
    const { slug } = req.params;

    const { data: group, error } = await supabaseAdmin
      .from("groups")
      .select("*,
        profiles(first_name, last_name)
      ")
      .eq("public_link_slug", slug)
      .eq("public_website_enabled", true)
      .single();

    if (error) {
      console.error("Supabase error fetching public group:", error);
      return res.status(500).json({ error: error.message });
    }

    if (!group) {
      return res.status(404).json({ error: "Public group not found or not enabled" });
    }

    res.status(200).json({
      id: group.id,
      name: group.name,
      description: group.description,
      group_type: group.group_type,
      cover_image_url: group.cover_image_url,
      announcements_content: group.announcements_content,
      program_outline_content: group.program_outline_content,
      contact_email: group.contact_email,
      contact_phone: group.contact_phone,
      public_link_slug: group.public_link_slug,
      leader_name: group.profiles ? `${group.profiles.first_name} ${group.profiles.last_name}` : null,
      join_link_enabled: group.join_link_enabled,
    });

  } catch (error: any) {
    console.error("Error fetching public group:", error);
    res.status(500).json({ error: error.message || "Failed to fetch public group" });
  }
});

async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);

    try {
      const { data: branches, error } = await supabaseAdmin.from("branches").select("id, name");
      if (error) {
        console.error("Error fetching branches for debug:", error);
      } else {
        console.log("EXISTING SUPABASE BRANCHES (for debug):");
        if (branches && branches.length > 0) {
          branches.forEach(b => console.log(`  ID: ${b.id}, Name: ${b.name}`));
        } else {
          console.log("  No branches found.");
        }
      }
    } catch (debugError) {
      console.error("Unexpected error during branch debug logging:", debugError);
    }

  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();

